/**
 * Pass the body straight to @simplewebauthn/browser's startRegistration. The challenge is returned in a signed cookie and is single-use.
 * @summary WebAuthn creation options
 */
export const GetPasskeyRegistrationOptionsResponse = zod.record(
  zod.string(),
  zod.unknown(),
);

/**
 * @summary Store a passkey after verifying the attestation
 */
export const VerifyPasskeyRegistrationBody = zod
  .record(zod.string(), zod.unknown())
  .describe("The attestation from startRegistration, plus an optional `name`.");

/**
 * No identifier is asked for: the authenticator says which credential it holds.
 * @summary WebAuthn request options (usernameless)
 */
export const GetPasskeyLoginOptionsResponse = zod.record(
  zod.string(),
  zod.unknown(),
);

/**
 * Answers `requires2fa` when the account also has TOTP on — a passkey does not override a second factor its owner turned on here.
 * @summary Sign in with a passkey
 */
export const VerifyPasskeyLoginBody = zod
  .record(zod.string(), zod.unknown())
  .describe("The assertion from startAuthentication.");

export const VerifyPasskeyLoginResponse = zod
  .union([
    zod.object({
      requires2fa: zod.literal(true),
      mfaToken: zod
        .string()
        .describe(
          "Short-lived, and carries a distinct JWT audience — it cannot be used as a session token.",
        ),
    }),
    zod.object({
      token: zod.string(),
      user: zod.object({
        id: zod.number(),
        nickname: zod.string(),
        email: zod.string(),
        avatarUrl: zod.string().nullish(),
        points: zod.number(),
        role: zod.enum(["user", "author", "moderator", "admin"]),
        emailVerified: zod.boolean(),
        isBlocked: zod.boolean(),
        createdAt: zod.coerce.date(),
      }),
    }),
  ])
  .describe(
    "A correct password does not always mean a session: an account with 2FA gets an mfaToken to exchange at \/auth\/2fa\/verify instead.",
  );

